import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Venue } from '../../core/models';

/**
 * GatherUp venue create/edit form (organizer). Shared by /organizer/venues/new
 * and /organizer/venues/:id. Mock data in signals; service_agent wires
 * ApiService.getVenue()/createVenue()/updateVenue().
 */
@Component({
  selector: 'app-venue-form',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './venue-form.component.html',
  styleUrl: './venue-form.component.css',
})
export class VenueFormComponent implements OnInit {
  readonly isEdit = signal(false);
  readonly saving = signal(false);
  readonly error = signal<string | null>(null);

  // Seed venues so an edit route can prefill; cleared by mockup_cleaner.
  readonly venues = signal<Venue[]>([
    { id: 'v1', name: 'The Warehouse', address: '12 Dock Road, Riverside', defaultCapacity: 150 },
    { id: 'v2', name: 'Riverside Hall', address: '5 Canal Street, Old Town', defaultCapacity: 80 },
    { id: 'v3', name: 'Rooftop 22', address: '22 Skyline Ave', defaultCapacity: 60 },
  ]);

  form: { name: string; address: string; defaultCapacity: number } = {
    name: '', address: '', defaultCapacity: 50,
  };

  constructor(private route: ActivatedRoute, private router: Router) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.isEdit.set(true);
      const existing = this.venues().find((v) => v.id === id);
      if (existing) {
        this.form = {
          name: existing.name,
          address: existing.address,
          defaultCapacity: existing.defaultCapacity,
        };
      }
      // service_agent: this.api.getVenue(id).subscribe(v => this.form = {...});
    }
  }

  save(): void {
    if (!this.form.name || !this.form.address) {
      this.error.set('Name and address are required.');
      return;
    }
    this.saving.set(true);
    this.error.set(null);
    // service_agent: create or update via ApiService, then navigate on success.
    this.router.navigate(['/organizer/venues']);
  }

  cancel(): void {
    this.router.navigate(['/organizer/venues']);
  }
}
